<template>
    <div class="card mb-0 pt-2 pt-md-0">
        <div class="card-header bg-primary">
            <h6 class="my-0 text-white">Reporte de Caja</h6>
        </div>
        <div class="tab-content p-3">
            <form autocomplete="off" @submit.prevent="submit">
                <div class="form-body">
                    <div class="row">
                        <template>
                            <div class="col-md-3">
                                <label class="control-label w-100"
                                    >Fecha de Cierre</label
                                >
                                <el-date-picker
                                    class="w-100"
                                    v-model="form.date_close"
                                    type="date"
                                    @change="changeDisabledDates"
                                    value-format="yyyy-MM-dd"
                                    format="dd/MM/yyyy"
                                    clearable
                                ></el-date-picker>
                            </div>
                        </template>
                        <template v-if="restaurant">
                            <div class="col-md-3">
                                <label class="control-label">Usuario</label>
                                <el-select
                                    v-model="form.user_id"
                                    clearable
                                    @change="date_start()"
                                >
                                    <el-option
                                        v-for="(data, idx) in users"
                                        :key="idx"
                                        :label="data.name"
                                        :value="data.id"
                                    ></el-option>
                                </el-select>
                            </div>
                        </template>
                        <div
                            class="col-lg-7 col-md-7 col-md-7 col-sm-12"
                            style="margin-top: 29px"
                        >
                            <el-button
                                class="submit"
                                type="success"
                                @click.prevent="getRecords"
                                :loading="loading_submit"
                                icon="el-icon-search"
                                >Buscar</el-button
                            >

                            <template v-if="records.length > 0">
                                <el-button
                                    class="submit"
                                    type="danger"
                                    icon="el-icon-tickets"
                                    @click.prevent="clickDownload('pdf')"
                                    >Exportar PDF</el-button
                                >
                            </template>
                            <template v-if="records.length > 0">
                                <el-button
                                    class="submit"
                                    type="success"
                                    icon="el-icon-tickets"
                                    @click.prevent="clickDownload('excel')"
                                    >Exportar EXCEL</el-button
                                >
                            </template>
                        </div>
                    </div>
                    <div class="row" v-if="records.length > 0">
                        <div class="col-md-12">
                            <div class="table-responsive mt-2">
                                <table class="table table-striped">
                                    <thead>
                                        <tr>
                                            <th>#</th>
                                            <th>Fecha</th>
                                            <th>Operacion</th>
                                            <th>Referencia</th>
                                            <th>Cliente</th>
                                            <th>Concepto</th>
                                            <th>Usuario</th>
                                            <th>Monto</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        <tr
                                            v-for="(row, index) in records"
                                            :key="index"
                                        >
                                            <td scope="row">
                                                {{ customIndex(index) }}
                                            </td>
                                            <td>{{ row.date }}</td>
                                            <td>{{ row.type }}</td>
                                            <td>{{ row.reference }}</td>
                                            <td>{{ row.cliente }}</td>
                                            <td>{{ row.description }}</td>
                                            <td>{{ row.user }}</td>
                                            <td>{{ row.amount }}</td>
                                        </tr>
                                        <tr>
                                            <td class="text-end" colspan="7">
                                                Total Gastos
                                            </td>
                                            <td class="text-center">
                                                {{ totals_egresos }}
                                            </td>
                                        </tr>
                                        <tr>
                                            <td class="text-end" colspan="7">
                                                Total Ingreso
                                            </td>
                                            <td class="text-center">
                                                {{ totals_ingresos }}
                                            </td>
                                        </tr>
                                        <tr>
                                            <td class="text-end" colspan="7">
                                                Total Efectivo
                                            </td>
                                            <td class="text-center">
                                                {{ totals_efectivos }}
                                            </td>
                                        </tr>
                                        <tr>
                                            <td class="text-end" colspan="7">
                                                Total Depositos - Transferencias
                                            </td>
                                            <td class="text-center">
                                                {{ totals_depositos }}
                                            </td>
                                        </tr>
                                        <tr>
                                            <td class="text-end" colspan="7">
                                                Total S/
                                            </td>
                                            <td class="text-center">
                                                {{
                                                    totals_depositos +
                                                        totals_efectivos
                                                }}
                                            </td>
                                        </tr>
                                    </tbody>
                                </table>
                                <div>
                                    <el-pagination
                                        @current-change="getRecords"
                                        layout="total, prev, pager, next"
                                        :total="pagination.total"
                                        :current-page.sync="
                                            pagination.current_page
                                        "
                                        :page-size="pagination.per_page"
                                    >
                                    </el-pagination>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </form>
        </div>
    </div>
</template>

<script>
import moment from "moment";
import queryString from "query-string";
import BoxModal from "./options.vue";
export default {
    props: ["showDialog_report", "restaurant", "users"],
    components: { BoxModal },
    data() {
        return {
            loading_submit: false,
            titleDialog: null,
            resource: "expensesbox",
            form: {},
            array_subcategorias: [],
            array_categorias: [],
            array_group: [],
            register_group: false,
            register_category: false,
            register_subcategory: false,
            form_group: [],
            form_category: [],
            form_subcategory: [],
            pagination: {},
            search: {},
            pagination: {},
            records: [],
            totals_ingresos: 0,
            totals_egresos: 0,
            totals_efectivos: 0,
            totals_depositos: 0,
            modaltype: false,
            ruta: null,
            pickerOptionsDates: {
                disabledDate: time => {
                    time = moment(time).format("YYYY-MM-DD");
                    return this.form.date_start > time;
                }
            },
            pickerOptionsMonths: {
                disabledDate: time => {
                    time = moment(time).format("YYYY-MM");
                    return this.form.month_start > time;
                }
            }
        };
    },
    created() {
        this.initForm();
        this.$http.get(`/${this.resource}/tables`).then(response => {
            this.array_group = response.data.gruop;
            this.array_categorias = response.data.category;
            this.array_subcategorias = response.data.subcategory;
        });
        //            await this.$http.get(`/${this.resource}/record`)
        //                .then(response => {
        //                    if (response.data !== '') {
        //                        this.form = response.data.data
        //                    }
        //                })
    },
    methods: {
        customIndex(index) {
            return (
                this.pagination.per_page * (this.pagination.current_page - 1) +
                index +
                1
            );
        },
        initForm() {
            this.errors = {};
            this.form = {
                id: null,
                user_id: null,
                date_close: moment().format("YYYY-MM-DD"),
                type: "pdf",
                type_box: null,
                period: "month",
                date_start: null,
                date_end: moment().format("YYYY-MM-DD"),
                month_start: moment().format("YYYY-MM"),
                month_end: moment().format("YYYY-MM")
            };
        },
        date_start() {
            this.$http
                .get(`/${this.resource}/user/${this.form.user_id}`)
                .then(response => {
                    this.form.date_start = response.data;
                });
        },
        create() {
            this.titleDialog = "Reporte de Arqueo de Caja";
            if (this.recordId) {
                this.$http
                    .get(`/${this.resource}/record/${this.recordId}`)
                    .then(response => {
                        this.form = response.data.data;
                    });
            }
        },
        async getRecordsByFilter() {
            this.loading_submit = true;
            await this.getRecords();
            this.loading_submit = false;
        },
        getRecords() {
            // window.open(`/expensesbox/reports?${this.getQueryParameters()}`, '_blank');
            this.loading_submit = true;
            this.$http
                .get(`/expensesbox/reports?${this.getQueryParameters()}`)
                .then(response => {
                    this.records = response.data.data;
                    this.pagination = response.data.meta;
                    this.pagination.per_page = parseInt(
                        response.data.meta.per_page
                    );
                    this.loading_submit = false;
                    this.Totals();
                });
        },
        Totals() {
            let letIngresos = _.filter(this.records, {
                type: "Efectivo - Ingreso"
            });
            let depositos_total = _.filter(this.records, {
                type: "Transferencia - Ingreso"
            });
            let letEgresos = _.filter(this.records, { type: "Egreso" });
            this.totals_depositos = _.sumBy(depositos_total, it =>
                parseFloat(it.amount)
            );
            this.totals_ingresos = _.sumBy(letIngresos, it =>
                parseFloat(it.amount)
            );
            this.totals_egresos = _.sumBy(letEgresos, it =>
                parseFloat(it.amount)
            );
            this.totals_efectivos = _.round(
                this.totals_ingresos - this.totals_egresos,
                2
            );
        },
        getQueryParameters() {
            return queryString.stringify({
                page: this.pagination.current_page,
                limit: this.limit,
                ...this.form
            });
        },
        changeDisabledDates() {
            if (this.form.date_end < this.form.date_start) {
                this.form.date_end = this.form.date_start;
            }
            // this.loadAll();
        },
        changeDisabledMonths() {
            if (this.form.month_end < this.form.month_start) {
                this.form.month_end = this.form.month_start;
            }
            // this.loadAll();
        },
        changePeriod() {
            if (this.form.period === "month") {
                this.form.month_start = moment().format("YYYY-MM");
                this.form.month_end = moment().format("YYYY-MM");
            }
            if (this.form.period === "between_months") {
                this.form.month_start = moment()
                    .startOf("year")
                    .format("YYYY-MM"); //'2019-01';
                this.form.month_end = moment()
                    .endOf("year")
                    .format("YYYY-MM");
            }
            if (this.form.period === "date") {
                this.form.date_start = moment().format("YYYY-MM-DD");
                this.form.date_end = moment().format("YYYY-MM-DD");
            }
            if (this.form.period === "between_dates") {
                this.form.date_start = moment()
                    .startOf("month")
                    .format("YYYY-MM-DD");
                this.form.date_end = moment()
                    .endOf("month")
                    .format("YYYY-MM-DD");
            }
            // this.loadAll();
        },
        clickDownload(type) {
            this.modaltype = true;
            this.form.type = type;
            let form_data = this.form;
            let query = queryString.stringify({
                ...this.form
            });
            //expensesbox/reports_pd
            let ruta = `/expensesbox/reports_pdf?${query}`;
            if (type === "excel") {
                ruta = `/expensesbox/reports_excel?${query}`;
            }
            let link = `${ruta}`;
            window.open(`${link}`, "_blank");
        },
        close() {
            this.$emit("update:showDialog_report", false);
            this.initForm();
        }
    }
};
</script>



